boot.artifact:
// inferred-not-tested:样式必须进入 document.head
const css = document.createElement('link'); css.rel = 'stylesheet';
css.href = 'https://cdn.jsdelivr.net/npm/latex.css@1.14.0/style.min.css';
document.head.appendChild(css);
const el = document.getElementById('paper'); el.classList.toggle('latex-dark', data.theme === 'dark');
el.innerHTML = data.html;

boot.widget:
// widget 零足迹:CSS 只进入 shadowRoot
const css = document.createElement('link'); css.rel = 'stylesheet';
css.href = 'https://cdn.jsdelivr.net/npm/latex.css@1.14.0/style.min.css';
const el = document.createElement('article');
el.classList.toggle('latex-dark', data.theme === 'dark'); el.innerHTML = data.html;
shadowRoot.append(css, el);

